import re
from datetime import datetime
from typing import Any

def summarize_cloudwatch_logs(logs: list[dict[str, Any]]) -> dict[str, Any]:
    """
    Summarize AWS CloudWatch Logs query results.

    Args:
        logs: List of dictionaries with @timestamp and @message fields

    Returns:
        Dictionary with total_entries, date_range, and unique_message_prefixes
    """
    if not logs:
        return {
            "total_entries": 0,
            "date_range": None,
            "unique_message_prefixes": []
        }

    total_entries = len(logs)

    # Extract timestamps
    timestamps = []
    for log in logs:
        if "@timestamp" in log:
            try:
                ts = datetime.fromisoformat(log["@timestamp"].replace("Z", "+00:00"))
                timestamps.append(ts)
            except (ValueError, AttributeError):
                pass

    # Calculate date range
    date_range = None
    if timestamps:
        timestamps.sort()
        date_range = {
            "start": timestamps[0].isoformat(),
            "end": timestamps[-1].isoformat()
        }

    # Extract unique message prefixes
    prefixes = set()
    for log in logs:
        if "@message" in log:
            message = str(log["@message"])
            # Extract prefix (first word or up to first space/special char)
            match = re.match(r'^(\S+)', message)
            if match:
                prefix = match.group(1)
                prefixes.add(prefix)
            elif message:
                prefixes.add(message[:50])

    unique_message_prefixes = sorted(list(prefixes))

    return {
        "total_entries": total_entries,
        "date_range": date_range,
        "unique_message_prefixes": unique_message_prefixes
    }
